class Solution:
    def countPairs(self, nums: List[int], low: int, high: int) -> int:
        class TrieNode:
            __slots__ = ['children', 'cnt']
            def __init__(self):
                self.children = [None, None]
                self.cnt = 0

        root = TrieNode()
        ans = 0

        def insert(num):
            node = root
            for i in range(15, -1, -1):
                bit = (num >> i) & 1
                if not node.children[bit]:
                    node.children[bit] = TrieNode()
                node = node.children[bit]
                node.cnt += 1

        def query(num, limit):
            node = root
            res = 0
            for i in range(15, -1, -1):
                if not node:
                    break
                bit_num = (num >> i) & 1
                bit_limit = (limit >> i) & 1
                if bit_limit:
                    if node.children[bit_num]:
                        res += node.children[bit_num].cnt
                    node = node.children[1 - bit_num]
                else:
                    node = node.children[bit_num]
            return res

        for num in nums:
            ans += query(num, high) - query(num, low - 1)
            insert(num)
        return ans
```
efficiency: HIGH
time complexity: O(N log M) where M is the maximum value in nums (2^15 bits)
space complexity: O(N log M)
energy implications: LOW
explanation: Uses a 16-bit binary trie to count XOR pairs ≤ high and ≤ low-1 in O(log M) per number, then subtracts to get the range count. Efficient for N up to 2×10^4.

